arguments.file_text:
@code {
    [Parameter] public EventCallback<Order> OnOrderPlaced { get; set; }

    private Order _order = new();
    private int _step = 0;

    private void GoToPayment()
    {
        _step = 1;
    }

    private void GoBackToShipping()
    {
        _step = 0;
    }

    private async Task PlaceOrderAsync()
    {
        await OnOrderPlaced.InvokeAsync(_order);
    }
}

@if (_step == 0)
{
    <ShippingStep Shipping="_order.Shipping" OnNext="GoToPayment" />
}
else
{
    <PaymentStep Payment="_order.Payment"
                 OnBack="GoBackToShipping"
                 OnPlaceOrder="PlaceOrderAsync" />
}

@implements IDisposable
@inject IAddressValidator AddressValidator

@code {
    [Parameter] public ShippingInfo Shipping { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }

    private bool _isValidating;
    private string? _validationError;
    private CancellationTokenSource? _cts;

    private async Task ValidateAndProceedAsync()
    {
        // Cancel any in-flight validation (e.g. user went back and changed fields).
        CancelPendingValidation();

        _validationError = null;
        _isValidating = true;

        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        try
        {
            var isValid = await AddressValidator.ValidateAddressAsync(
                Shipping.Address, Shipping.City, Shipping.ZipCode, token);

            token.ThrowIfCancellationRequested();

            if (isValid)
            {
                await OnNext.InvokeAsync();
            }
            else
            {
                _validationError = "The address could not be verified. Please check your details.";
            }
        }
        catch (OperationCanceledException)
        {
            // Validation was cancelled — nothing to do.
        }
        finally
        {
            _isValidating = false;
        }
    }

    private void CancelPendingValidation()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose()
    {
        CancelPendingValidation();
    }
}

<h3>Shipping Information</h3>

<label>
    Name
    <input @bind="Shipping.Name" disabled="@_isValidating" />
</label>

<label>
    Address
    <input @bind="Shipping.Address" disabled="@_isValidating" />
</label>

<label>
    City
    <input @bind="Shipping.City" disabled="@_isValidating" />
</label>

<label>
    Zip Code
    <input @bind="Shipping.ZipCode" disabled="@_isValidating" />
</label>

@if (_validationError is not null)
{
    <p class="validation-error">@_validationError</p>
}

<button @onclick="ValidateAndProceedAsync" disabled="@_isValidating">
    @if (_isValidating)
    {
        <span class="spinner" aria-hidden="true"></span>
        <span>Validating…</span>
    }
    else
    {
        <span>Next</span>
    }
</button>

@code {
    [Parameter] public PaymentInfo Payment { get; set; } = default!;
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnPlaceOrder { get; set; }

    private bool _isSubmitting;

    private async Task HandlePlaceOrderAsync()
    {
        _isSubmitting = true;
        try
        {
            await OnPlaceOrder.InvokeAsync();
        }
        finally
        {
            _isSubmitting = false;
        }
    }
}

<h3>Payment Information</h3>

<label>
